const incoming = $input.first()?.json ?? {};
const body = incoming.body ?? incoming;

const courseName = body.course_name || body.courseName || "Unknown Course";
const courseId = body.course_id || body.courseId || "course_unknown";
const studentId = body.student_id || body.studentId || "student_unknown";

const rawSelfAssessments = [
  ...(Array.isArray(body.student_inputs) ? body.student_inputs : []),
  ...(Array.isArray(body.studentInputs) ? body.studentInputs : []),
  ...(Array.isArray(body.self_assessments) ? body.self_assessments : []),
  ...(Array.isArray(body.selfAssessments) ? body.selfAssessments : [])
];

const rawMistakes = [
  ...(Array.isArray(body.mistake_records) ? body.mistake_records : []),
  ...(Array.isArray(body.mistakeRecords) ? body.mistakeRecords : []),
  ...(Array.isArray(body.wrong_questions) ? body.wrong_questions : []),
  ...(Array.isArray(body.wrongQuestions) ? body.wrongQuestions : []),
  ...(Array.isArray(body.mistakes) ? body.mistakes : [])
];

const timeConstraints = body.time_constraints || body.timeConstraints || {};
const targetLevel = body.target_level || body.targetLevel || body.target_score || body.targetScore || timeConstraints.target_level || timeConstraints.targetLevel || null;
const studentText = body.student_text || body.studentText || body.text || "";

const profileSources = [];

if (studentText) {
  profileSources.push({
    source_id: body.student_text_source_id || body.studentTextSourceId || "student_text_001",
    source_type: "student_text",
    topic: null,
    question_id: null,
    text: studentText,
    metadata: {}
  });
}

rawSelfAssessments.forEach((source, index) => {
  profileSources.push({
    source_id: source.source_id || source.sourceId || `self_eval_${String(index + 1).padStart(3, "0")}`,
    source_type: source.source_type || source.sourceType || "self_assessment",
    topic: source.topic || source.topic_or_concept || source.topicOrConcept || null,
    question_id: source.question_id || source.questionId || null,
    text: source.text || source.content || source.note || "",
    metadata: source.metadata || {}
  });
});

rawMistakes.forEach((source, index) => {
  profileSources.push({
    source_id: source.source_id || source.sourceId || `mistake_${String(index + 1).padStart(3, "0")}`,
    source_type: source.source_type || source.sourceType || "mistake_record",
    topic: source.topic || source.topic_or_concept || source.topicOrConcept || null,
    question_id: source.question_id || source.questionId || source.id || null,
    text: source.text || source.content || source.note || source.explanation || "",
    metadata: source.metadata || {}
  });
});

const daysLeft = timeConstraints.days_left ?? timeConstraints.daysLeft ?? body.days_left ?? body.daysLeft ?? null;
const hoursPerDay = timeConstraints.hours_per_day ?? timeConstraints.hoursPerDay ?? body.hours_per_day ?? body.hoursPerDay ?? null;
const explicitTotalHours = timeConstraints.estimated_total_hours ?? timeConstraints.estimatedTotalHours ?? body.estimated_total_hours ?? body.estimatedTotalHours ?? body.available_hours ?? body.availableHours ?? null;
const estimatedTotalHours = explicitTotalHours ?? ((Number.isFinite(Number(daysLeft)) && Number.isFinite(Number(hoursPerDay))) ? Number(daysLeft) * Number(hoursPerDay) : null);

const normalizedTimeConstraints = {
  days_left: daysLeft,
  hours_per_day: hoursPerDay,
  estimated_total_hours: estimatedTotalHours,
  unavailable_periods: timeConstraints.unavailable_periods || timeConstraints.unavailablePeriods || [],
  deadline: timeConstraints.deadline || body.deadline || null,
  raw: timeConstraints
};

return [{
  json: {
    workflow_name: "student_profile_agent",
    course_id: courseId,
    course_name: courseName,
    student_id: studentId,
    profile_input_summary: {
      self_assessment_count: rawSelfAssessments.length + (studentText ? 1 : 0),
      mistake_record_count: rawMistakes.length,
      has_time_constraints: Object.keys(timeConstraints).length > 0 || daysLeft !== null || hoursPerDay !== null || explicitTotalHours !== null,
      has_target: Boolean(targetLevel),
      total_profile_sources: profileSources.length
    },
    target_level_hint: targetLevel,
    profile_sources: profileSources,
    time_constraints: normalizedTimeConstraints,
    constraints: {
      no_exam_prediction: true,
      no_score_prediction: true,
      no_final_review_plan: true,
      no_medical_or_psychological_diagnosis: true,
      evidence_required_for_each_weakness: true
    }
  }
}];

const data = $input.first().json;

const profilePreview = (data.profile_sources || []).map(source => ({
  source_id: source.source_id,
  source_type: source.source_type,
  topic: source.topic,
  question_id: source.question_id,
  metadata: source.metadata,
  text: (source.text || "").slice(0, 5000)
}));

const systemPrompt = `You are Student Profile Agent in CourseLens, a multi-agent course review system.

Your only job is to build an evidence-grounded student profile from self-assessments, mistake records, time constraints, target level, and learning preferences.

Rules:
1. Extract student profile information only: self-assessed mastery, weaknesses, mistake patterns, time constraints, learning preferences, and learning-risk flags.
2. Every weakness and mistake pattern should include evidence from the provided student input or mistake records when possible.
3. Do not generate a complete review plan or day-by-day schedule.
4. Do not predict exam questions.
5. Do not predict the student's final score or guarantee any target outcome.
6. Do not make medical or psychological diagnoses. Treat emotion or anxiety signals only as learning constraints or risk flags.
7. Do not fuse with course materials, lecture signals, or exam patterns. This agent only describes the student state.
8. If information is weak, ambiguous, or missing, mark it in uncertainties.
9. Return valid JSON only. Do not wrap it in Markdown. Do not add explanations outside JSON.`;

const userPrompt = `Build a Student Profile Map for the course below.

Course ID: ${data.course_id}
Course name: ${data.course_name}
Student ID: ${data.student_id}

Profile input summary:
${JSON.stringify(data.profile_input_summary, null, 2)}

Target level hint:
${JSON.stringify(data.target_level_hint, null, 2)}

Time constraints:
${JSON.stringify(data.time_constraints, null, 2)}

Profile sources:
${JSON.stringify(profilePreview, null, 2)}

Return this exact JSON shape:
{
  "workflow_name": "student_profile_agent",
  "course_id": "${data.course_id}",
  "course_name": "${data.course_name}",
  "student_id": "${data.student_id}",
  "profile_summary": {
    "target_level": "string_or_null",
    "available_study_time_hours": number_or_null,
    "overall_self_confidence": "unknown | low | medium | high | mixed",
    "main_constraints": ["string"]
  },
  "knowledge_self_assessment": [
    {
      "topic_or_concept": "string",
      "self_assessed_level": "unknown | low | medium | high | mixed",
      "confidence": 0.75,
      "evidence": [
        {
          "source_id": "string",
          "source_type": "student_text | self_assessment | mistake_record | wrong_question | other",
          "evidence_text": "short direct evidence from the student input"
        }
      ],
      "notes": "string"
    }
  ],
  "weaknesses": [
    {
      "weakness_id": "stable short id such as sw_001",
      "topic_or_concept": "string",
      "weakness_type": "conceptual | calculation | application | memory | comparison | analysis | confidence | time_management | unknown",
      "severity": "low | medium | high",
      "confidence": 0.85,
      "evidence": [
        {
          "source_id": "string",
          "source_type": "student_text | self_assessment | mistake_record | wrong_question | other",
          "evidence_text": "short direct evidence from the student input"
        }
      ],
      "likely_reason": "string_or_null"
    }
  ],
  "mistake_patterns": [
    {
      "pattern_id": "stable short id such as mp_001",
      "topic_or_concept": "string",
      "mistake_type": "concept_confusion | formula_application | calculation_error | memory_gap | method_selection | interpretation_error | unknown",
      "related_questions": ["question_id"],
      "summary": "string",
      "evidence": [
        {
          "source_id": "string",
          "source_type": "mistake_record | wrong_question | student_text | other",
          "evidence_text": "short direct evidence from the mistake record"
        }
      ]
    }
  ],
  "time_profile": {
    "days_left": number_or_null,
    "hours_per_day": number_or_null,
    "estimated_total_hours": number_or_null,
    "time_pressure": "unknown | low | medium | high",
    "notes": "string"
  },
  "learning_preferences": {
    "preferred_methods": ["string"],
    "avoid_methods": ["string"],
    "evidence": [
      {
        "source_id": "string",
        "source_type": "string",
        "evidence_text": "short direct evidence"
      }
    ]
  },
  "risk_flags": [
    {
      "risk_type": "limited_time | broad_weakness | low_confidence | missing_information | high_target_pressure | unbalanced_profile",
      "severity": "low | medium | high",
      "description": "string",
      "evidence": [
        {
          "source_id": "string",
          "source_type": "string",
          "evidence_text": "short direct evidence"
        }
      ]
    }
  ],
  "uncertainties": ["string"]
}

Quality requirements:
- Use source_id and source_type exactly as given.
- Keep evidence_text short.
- Confidence must be between 0 and 1.
- Do not create a detailed review schedule.
- Do not predict the student's score.
- If target level is mentioned, summarize it as a goal, not as a predicted outcome.
- If emotional language appears, describe it only as a learning risk or constraint, not as a diagnosis.`;

return [{
  json: {
    ...data,
    llm_payload: {
      system_prompt: systemPrompt,
      user_prompt: userPrompt
    }
  }
}];

const llmResult = $input.first().json;

function pickRawOutput(value) {
  if (typeof value === "string") return value;
  if (value?.output !== undefined) return value.output;
  if (value?.response?.text !== undefined) return value.response.text;
  if (value?.generations?.[0]?.[0]?.text !== undefined) return value.generations[0][0].text;
  if (value?.choices?.[0]?.message?.content !== undefined) return value.choices[0].message.content;
  if (value?.text !== undefined) return value.text;
  if (value?.response !== undefined) return value.response;
  if (value?.message?.content !== undefined) return value.message.content;
  return value;
}

function stripCodeFence(text) {
  return text
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/\s*```$/i, "")
    .trim();
}

function parseJsonLoose(raw) {
  if (raw && typeof raw === "object") {
    if (raw.workflow_name || raw.profile_summary || raw.weaknesses) return raw;
    raw = JSON.stringify(raw);
  }

  let text = String(raw ?? "").trim();
  text = stripCodeFence(text);

  try {
    return JSON.parse(text);
  } catch (firstError) {
    const start = text.indexOf("{");
    const end = text.lastIndexOf("}");
    if (start >= 0 && end > start) {
      const candidate = text.slice(start, end + 1);
      return JSON.parse(candidate);
    }
    throw firstError;
  }
}

let parsed;
try {
  parsed = parseJsonLoose(pickRawOutput(llmResult));
} catch (error) {
  return [{
    json: {
      workflow_name: "student_profile_agent",
      parser_error: true,
      error_message: error.message,
      raw_llm_output: llmResult
    }
  }];
}

parsed.workflow_name = parsed.workflow_name || "student_profile_agent";
parsed.profile_summary = parsed.profile_summary || {};
parsed.knowledge_self_assessment = Array.isArray(parsed.knowledge_self_assessment) ? parsed.knowledge_self_assessment : [];
parsed.weaknesses = Array.isArray(parsed.weaknesses) ? parsed.weaknesses : [];
parsed.mistake_patterns = Array.isArray(parsed.mistake_patterns) ? parsed.mistake_patterns : [];
parsed.time_profile = parsed.time_profile || {};
parsed.learning_preferences = parsed.learning_preferences || { preferred_methods: [], avoid_methods: [], evidence: [] };
parsed.risk_flags = Array.isArray(parsed.risk_flags) ? parsed.risk_flags : [];
parsed.uncertainties = Array.isArray(parsed.uncertainties) ? parsed.uncertainties : [];
parsed._agent_meta = {
  parsed_at: new Date().toISOString(),
  node: "Parse OpenAI JSON"
};

return [{ json: parsed }];
